mapper.select:
SELECT S.STAY_ID, S.NAME, S.ADDR, S.LAT, S.LNG, S.FACILITIES, NVL(R.MIN_PRICE, 0) AS minPrice, NVL(R.ROOM_CNT, 0) AS roomCount, (SELECT F.FILE_URL FROM TB_FILE F WHERE F.REF_TYPE = 'STAY' AND F.REF_ID = S.STAY_ID AND ROWNUM = 1 ) AS THUMB_PATH FROM TB_STAY S LEFT JOIN ( SELECT STAY_ID, MIN(PRICE_PER_NIGHT) AS MIN_PRICE, COUNT(*) AS ROOM_CNT FROM TB_STAY_ROOM WHERE STATUS_CD = 'APPROVE' GROUP BY STAY_ID ) R ON S.STAY_ID = R.STAY_ID WHERE S.STATUS_CD IN ('ACTIVE', 'NORMAL')
AND S.REGION = #{region}
AND S.FACILITIES LIKE '%' || #{fac} || '%'
AND NVL(R.MIN_PRICE, 0) <= #{maxPrice}
ORDER BY NVL(R.MIN_PRICE, 999999999) ASC
ORDER BY S.STAY_ID

SELECT COUNT(*)
  FROM TB_RESERVATION
 WHERE ROOM_ID       = #{roomId}
   AND RESV_TYPE     = 'STAY'
   AND STATUS_CD     IN ('PENDING', 'CONFIRMED')
   AND CHECKIN_DATE  < #{checkoutDate}
   AND CHECKOUT_DATE > #{checkinDate}

mapper.update:
UPDATE TB_RESERVATION
   SET STATUS_CD = #{statusCd}
 WHERE RESV_ID   = #{resvId}

UPDATE TB_MEMBER
   SET POINT_BALANCE = NVL(POINT_BALANCE, 0) - #{pointAmount}
 WHERE MEMBER_NO = #{memberNo}
